// 1) Ordenamos por fecha
items.sort((a, b) => new Date(a.json.createdAt) - new Date(b.json.createdAt));

// 2) Construimos el texto combinado
const lines = items.map((item, index) => {
    return `Message ${index + 1}: ${item.json.text}`;
});

// 3) Obtenemos el sessionId del primer ítem
const sessionId = items[0].json.sessionId;

// 4) Obtenemos accountId y conversationId desde Webhook2
const webhookData = $items("Webhook2")[0].json.body;

const accountId = webhookData.account.id;
const conversationId = webhookData.conversation.id;

// 5) Devolvemos un único item
return [
  {
    json: {
      sessionId,
      combinedMessages: lines.join('\n'),
      accountId,
      conversationId
    }
  }
];

// Function node en n8n

return items.map(item => {
  const body = item.json.body || {};
  const payment = (body.data && body.data.object) ? body.data.object : {};

  const amount = payment.amount;
  const status = payment.status;

  if (typeof amount === 'number' && status === 'succeeded') {
    // Stripe envía el importe en céntimos
    const euros = (amount / 100).toFixed(2).replace('.', ','); // 150 -> "1,50"

    const mensaje = `Mensaje de Stripe: Hemos recibido correctamente un pago de ${euros} €`;

    item.json.mensaje = mensaje;
    item.json.amount = amount;
    item.json.status = status;

  } else {
    // Pagos NO OK (fallidos, cancelados, etc.)
    const estado = status || 'desconocido';
    item.json.mensaje = `Mensaje de Stripe: el pago no se ha completado (estado: ${estado}).`;
    item.json.amount = amount;
    item.json.status = status;
  }

  return item;
});

